import{_ as t,o as r,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"14. Flexible Working Arrangements","description":"","frontmatter":{"title":"14. Flexible Working Arrangements","eba":"Medical Specialists 2022-2026","topics":["flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/consultation-disputes/14-flexible-working-arrangements.md","filePath":"ebas/medical-specialists/consultation-disputes/14-flexible-working-arrangements.md"}'),n={name:"ebas/medical-specialists/consultation-disputes/14-flexible-working-arrangements.md"};function a(i,e,l,c,g,p){return r(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_14-flexible-working-arrangements" tabindex="-1">14. Flexible Working Arrangements <a class="header-anchor" href="#_14-flexible-working-arrangements" aria-label="Permalink to &quot;14. Flexible Working Arrangements&quot;">​</a></h1><p><strong>14.1</strong> The Act entitles Doctors with at least 12 months continuous service (as defined in the Act) to request flexible working arrangements in specified circumstances.</p><p><strong>14.2</strong> The specified circumstances are if the Doctor:</p><p><strong>(a)</strong> is the parent, or has responsibility for the care, of a child who is of school age or younger;</p><p><strong>(b)</strong> is a carer within the meaning of the Carer Recognition Act 2010 (Vic) (for example, caring for someone who has a disability, a medical condition (including a terminal or chronic illness), a mental illness or is frail or aged);</p><p><strong>(c)</strong> has a disability;</p><p><strong>(d)</strong> is aged 55 years or older;</p><p><strong>(e)</strong> is experiencing violence from a member of the Doctor’s family; or</p><p><strong>(f)</strong> provides care or support to a member of the Doctor’s immediate family, or a member of the Doctor’s household, who requires care or support because the member is experiencing violence or abuse from the member’s family.</p><p><strong>14.3</strong> Changes in working arrangements may include, but are not limited to, hours of work, patterns of work and location of work (including in accordance with subclause 54.2(a)).</p><p><strong>14.4</strong> The request must be in writing, set out details of the change sought and the reasons for the change.</p><p><strong>14.5</strong> The Health Service must give the Doctor a written response to the request within 21 days, stating whether the Health Service grants or refuses the request. A request may only be refused on reasonable business grounds as described in the NES.</p><p><strong>14.6</strong> Where the Health Service refuses the request, the written response must include details of the reasons for the refusal.</p><p><strong>14.7</strong> Where a request for flexible work arrangements is made, a Doctor or Health Service is entitled to meet with the other party to discuss:</p><p><strong>(a)</strong> the request;</p><p><strong>(b)</strong> an alternative to the request; or</p><p><strong>(c)</strong> reasons for a refusal on reasonable business grounds.</p><p><strong>14.8</strong> A Doctor or Health Service may choose to be represented at a meeting under subclause</p><p><strong>14.7</strong> by a representative including the Association or employer organisation.</p><p><strong>14.9</strong> The dispute resolution procedure in this Agreement will apply to any dispute / grievance arising in relation to a request for flexible working arrangements.</p><p><strong>14.10</strong> Other entitlements relevant to family violence can be found at <a href="/eba/ebas/medical-specialists/leave/60-family-violence-leave.html">clause 60</a> (Family Violence Leave).</p><p>Plain language terms: flex work, flexible hours, WFH.</p>',22)])])}const u=t(n,[["render",a]]);export{m as __pageData,u as default};
